def _canonicalize_value(value: Any) -> Any:
    """Recursively canonicalize a value for stable, deterministic serialization.

    Dict keys are sorted recursively, tuples are converted to lists, and strings are
    stripped of leading/trailing whitespace. Numeric and boolean types are left untouched.
    """
    if isinstance(value, dict):
        return {k: _canonicalize_value(v) for k, v in sorted(value.items())}
    if isinstance(value, (list, tuple)):
        return [_canonicalize_value(v) for v in value]
    if isinstance(value, str):
        return value.strip()
    return value


def parse_python_calls(text: str) -> dict[str, Any]:
    """Parse one or more Python-style function call expressions into the `tool_calls` dict format.

    Only a minimal, safe subset of Python is accepted: top-level call expressions (e.g.
    `search(q="nlp")`), with keyword-only arguments whose values are literals (strings, numbers,
    booleans, `None`, and dicts/lists/tuples thereof). No names, attribute values, nested calls,
    comprehensions, or other dynamic constructs are allowed.

    Args:
        text: A string containing one or more Python-style function calls, e.g.
            `search(q="nlp")` or `search(q="nlp"); translate(text="hi", lang="fr")`.

    Returns:
        A dict of the form `{"tool_calls": [{"name": ..., "args": {...}}, ...]}`, in source order.
    """
    try:
        tree = ast.parse(text.strip(), mode="exec")
    except SyntaxError as e:
        raise ValueError(f"Could not parse input as a Python function call: {e}") from e

    if not tree.body:
        raise ValueError("No function calls found in the input.")

    calls = []
    for stmt in tree.body:
        if not isinstance(stmt, ast.Expr) or not isinstance(stmt.value, ast.Call):
            raise ValueError(
                "Only function call expressions are supported, e.g. `search(q=\"nlp\")`."
            )
        calls.append(_parse_call_node(stmt.value))

    return {"tool_calls": calls}


def _parse_call_node(node: ast.Call) -> dict[str, Any]:
    name = _parse_callee_name(node.func)

    if node.args:
        raise ValueError(
            f"Only keyword arguments supported; found positional argument(s) for `{name}`. "
            f"Please use keyword arguments, e.g. `{name}(arg_name=value)`."
        )

    args = {}
    for keyword in node.keywords:
        if keyword.arg is None:
            raise ValueError(f"Only keyword arguments supported; found `**kwargs` expansion in `{name}`.")
        args[keyword.arg] = _parse_literal_node(keyword.value)

    return {"name": name, "args": args}


def _parse_callee_name(node: ast.AST) -> str:
    if isinstance(node, ast.Name):
        return node.id
    if isinstance(node, ast.Attribute):
        return node.attr
    raise ValueError("Could not determine the tool name; only plain or dotted names are supported.")


def _parse_literal_node(node: ast.AST) -> Any:
    if isinstance(node, ast.Constant):
        return node.value

    if isinstance(node, ast.UnaryOp) and isinstance(node.op, (ast.USub, ast.UAdd)):
